#!/usr/bin/env python3
from __future__ import annotations
import json
from pathlib import Path

ROOT = Path.cwd()
DATASETS = {'MSL': {'epochs': 3, 'anormly_ratio': 0.83, 'runner': 'run_msl_official_vs_v4_best_v3.py'}, 'SMAP': {'epochs': 3, 'anormly_ratio': 0.8, 'runner': 'run_smap_official_vs_v4_best.py'}, 'PSM': {'epochs': 1, 'anormly_ratio': 0.8, 'runner': 'run_psm_official_vs_v4_best.py'}, 'HAI': {'epochs': 3, 'anormly_ratio': 0.98, 'runner': 'run_hai_official_vs_v4_best.py'}, 'SMD': {'epochs': 3, 'anormly_ratio': 0.9, 'runner': 'run_smd_official_vs_v4_best.py'}, 'WADI': {'epochs': 3, 'anormly_ratio': 0.5, 'runner': 'run_wadi_official_default_vs_v4_best.py'}, 'PUMP': {'epochs': 3, 'anormly_ratio': 0.5, 'runner': 'run_pump_official_default_vs_v4_best.py'}, 'SKAB': {'epochs': 3, 'anormly_ratio': 0.5, 'runner': 'run_skab_official_default_vs_v4_best.py'}}
EXPERIMENT = {'default_seed': 42, 'default_score_mode': 'combined', 'threshold_protocol': 'percentile(train_score + test_score, 100 - anormly_ratio)', 'output_root': 'results/FIXED_COMBINED', 'checkpoint_policy': 'load_existing_checkpoint_by_default', 'point_adjustment': True}
EVALUATE = '#!/usr/bin/env python3\nfrom __future__ import annotations\n\nimport argparse\nimport importlib.util\nimport json\nimport sys\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\nDATASET_CONFIG = ROOT / "configs" / "datasets.json"\nEXPERIMENT_CONFIG = ROOT / "configs" / "experiment.json"\nENGINE_PATH = ROOT / "scripts" / "run_all_fixed_combined.py"\n\ndef read_json(path: Path) -> dict:\n    if not path.exists():\n        raise FileNotFoundError(f"Missing file: {path}")\n    return json.loads(path.read_text(encoding="utf-8"))\n\ndef load_engine():\n    if not ENGINE_PATH.exists():\n        raise FileNotFoundError(f"Missing evaluation engine: {ENGINE_PATH}")\n    spec = importlib.util.spec_from_file_location("asca_ad_eval_engine", str(ENGINE_PATH))\n    if spec is None or spec.loader is None:\n        raise RuntimeError(f"Cannot load engine: {ENGINE_PATH}")\n    module = importlib.util.module_from_spec(spec)\n    sys.modules["asca_ad_eval_engine"] = module\n    spec.loader.exec_module(module)\n    return module\n\ndef select_datasets(name: str, config: dict) -> list[str]:\n    name = name.strip().upper()\n    if name == "ALL":\n        return list(config.keys())\n    items = [x.strip().upper() for x in name.split(",") if x.strip()]\n    bad = [x for x in items if x not in config]\n    if bad:\n        raise ValueError(f"Unknown dataset(s): {bad}. Valid: {\', \'.join(config.keys())}")\n    return items\n\ndef make_output_dir(raw: str, custom: str | None) -> Path:\n    if custom:\n        path = Path(custom)\n        return path if path.is_absolute() else ROOT / path\n    name = raw.strip().upper().replace(",", "_")\n    return ROOT / "results" / "FIXED_COMBINED" / name\n\ndef main() -> None:\n    parser = argparse.ArgumentParser(description="Unified ASCA-AD evaluator.")\n    parser.add_argument("dataset", help="SKAB, PUMP, PSM, MSL, SMAP, HAI, SMD, WADI, or all")\n    parser.add_argument("--output-dir", default=None)\n    parser.add_argument("--seed", type=int, default=None)\n    parser.add_argument("--epochs", type=int, default=None)\n    parser.add_argument("--train-if-missing", action="store_true")\n    args = parser.parse_args()\n\n    dataset_cfg = read_json(DATASET_CONFIG)\n    exp_cfg = read_json(EXPERIMENT_CONFIG)\n    engine = load_engine()\n\n    datasets = select_datasets(args.dataset, dataset_cfg)\n    out_dir = make_output_dir(args.dataset, args.output_dir)\n    out_dir.mkdir(parents=True, exist_ok=True)\n\n    seed = int(args.seed) if args.seed is not None else int(exp_cfg.get("default_seed", 42))\n\n    print("=" * 80)\n    print("ASCA-AD fixed-combined evaluation")\n    print("=" * 80)\n    print(f"Project root : {ROOT}")\n    print(f"Datasets     : {\', \'.join(datasets)}")\n    print(f"Output dir   : {out_dir}")\n    print(f"Seed         : {seed}")\n    print("=" * 80)\n\n    results = []\n    failures = []\n\n    for dataset in datasets:\n        cfg = dataset_cfg[dataset]\n        ratio = float(cfg["anormly_ratio"])\n        epochs = int(args.epochs) if args.epochs is not None else int(cfg.get("epochs", 3))\n        try:\n            result = engine.evaluate_dataset(\n                root=ROOT,\n                dataset=dataset,\n                ratio=ratio,\n                output_root=out_dir,\n                seed=seed,\n                v4_epochs=epochs,\n                train_if_missing=args.train_if_missing,\n            )\n            result["dataset_config"] = cfg\n            results.append(result)\n        except Exception as exc:\n            print(f"[{dataset}] FAILED: {exc}", file=sys.stderr)\n            failures.append({"dataset": dataset, "error": str(exc)})\n\n    if results:\n        engine.write_global_outputs(out_dir, results)\n\n    if failures:\n        fail_path = out_dir / "failures.json"\n        fail_path.write_text(json.dumps(failures, ensure_ascii=False, indent=2), encoding="utf-8")\n        raise SystemExit(1)\n\n    print()\n    print("Done.")\n    print(f"Summary: {out_dir / \'summary.md\'}")\n\nif __name__ == "__main__":\n    main()\n'
SCORING = 'from __future__ import annotations\n\nimport numpy as np\n\ndef total_score(loss_local, loss_global):\n    return np.asarray(loss_local) + np.asarray(loss_global)\n\ndef gap_score(loss_local, loss_global):\n    return np.abs(np.asarray(loss_local) - np.asarray(loss_global))\n\ndef combined_score(loss_local, loss_global, gap_weight: float = 1.0):\n    local = np.asarray(loss_local)\n    global_ = np.asarray(loss_global)\n    return local + global_ + float(gap_weight) * np.abs(local - global_)\n\ndef percentile_threshold(train_scores, test_scores, anormly_ratio: float) -> float:\n    values = np.concatenate([\n        np.asarray(train_scores).reshape(-1),\n        np.asarray(test_scores).reshape(-1),\n    ], axis=0)\n    return float(np.percentile(values, 100.0 - float(anormly_ratio)))\n'
UTILS = 'from __future__ import annotations\n\nimport json\nimport random\nfrom pathlib import Path\n\nimport numpy as np\nimport torch\n\ndef project_root() -> Path:\n    return Path(__file__).resolve().parents[1]\n\ndef set_seed(seed: int) -> None:\n    random.seed(seed)\n    np.random.seed(seed)\n    torch.manual_seed(seed)\n    if torch.cuda.is_available():\n        torch.cuda.manual_seed_all(seed)\n\ndef read_json(path: str | Path) -> dict:\n    return json.loads(Path(path).read_text(encoding="utf-8"))\n\ndef write_json(data: dict, path: str | Path) -> None:\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n'
README = '# Scripts\n\nUnified experiment entry points.\n\nSingle dataset:\n\n    python scripts/evaluate.py SKAB\n    python scripts/evaluate.py PUMP\n    python scripts/evaluate.py MSL\n\nShort shell wrapper:\n\n    bash scripts/eval.sh SKAB\n\nAll datasets:\n\n    python scripts/evaluate.py all\n    bash scripts/eval_all.sh\n\nDefault output path:\n\n    results/FIXED_COMBINED/<DATASET>/\n\nDataset-specific parameters are stored in:\n\n    configs/datasets.json\n    configs/experiment.json\n'
EVAL_SH = '#!/usr/bin/env bash\nset -euo pipefail\ncd "$(dirname "$0")/.."\npython -u scripts/evaluate.py "${1:-SKAB}"\n'
EVAL_ALL_SH = '#!/usr/bin/env bash\nset -euo pipefail\ncd "$(dirname "$0")/.."\npython -u scripts/evaluate.py all\n'

def write(path: Path, text: str, executable: bool = False) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")
    if executable:
        path.chmod(0o755)

def main() -> None:
    if not (ROOT / "scripts" / "run_all_fixed_combined.py").exists():
        raise FileNotFoundError("scripts/run_all_fixed_combined.py not found")
    if not (ROOT / "scripts" / "dataset_runners").exists():
        raise FileNotFoundError("scripts/dataset_runners not found")

    write(ROOT / "configs" / "datasets.json", json.dumps(DATASETS, ensure_ascii=False, indent=2) + "\n")
    write(ROOT / "configs" / "experiment.json", json.dumps(EXPERIMENT, ensure_ascii=False, indent=2) + "\n")
    write(ROOT / "scripts" / "evaluate.py", EVALUATE, executable=True)
    write(ROOT / "scripts" / "eval.sh", EVAL_SH, executable=True)
    write(ROOT / "scripts" / "eval_all.sh", EVAL_ALL_SH, executable=True)
    write(ROOT / "asca_ad" / "scoring.py", SCORING)
    write(ROOT / "asca_ad" / "utils.py", UTILS)
    write(ROOT / "asca_ad" / "__init__.py", "\"\"\"ASCA-AD package.\"\"\"\n")
    write(ROOT / "scripts" / "README.md", README)
    print("Created unified evaluation entry.")
    print("Test with: python -u scripts/evaluate.py SKAB")

if __name__ == "__main__":
    main()
